from typing import get_args

CLIENT_METHODS: frozenset[str] = frozenset(get_args(ClientMethod))
SYNC_METHODS: frozenset[str] = frozenset(get_args(SyncMethod))

_binding: Any | None = None
_binding_loaded = False
_client_override: Any | None = None


def reset_native_cache() -> None:
    """Clear cached binding / test overrides (unit tests)."""
    global _binding, _binding_loaded, _client_override
    _binding = None
    _binding_loaded = False
    _client_override = None


def set_native_client_for_tests(client: Any | None) -> None:
    """Inject a fake SolvaPayClient for unit tests."""
    global _client_override
    _client_override = client


def load_native_binding() -> Any:
    """Load ``solvapay._solvapay`` once."""
    global _binding, _binding_loaded
    if _binding_loaded:
        return _binding
    try:
        from solvapay import _solvapay as binding

        _binding = binding
    except ImportError:
        _binding = None
    _binding_loaded = True
    return _binding


def reconstruct_envelope_error(error: dict[str, Any]) -> Exception:
    """Map envelope error JSON to SolvaPayError / PaywallError (§5.7)."""
    kind = error.get("kind")
    message = error.get("message") or "SolvaPay error"
    if kind == "Paywall":
        gate = error.get("gate") or {}
        if not isinstance(gate, dict):
            gate = {}
        return PaywallError(message, gate)
    err = SolvaPayError(message)
    if kind == "Api":
        if isinstance(error.get("status"), int):
            setattr(err, "status", error["status"])
        if isinstance(error.get("code"), str):
            setattr(err, "code", error["code"])
    elif isinstance(error.get("code"), str):
        setattr(err, "code", error["code"])
    return err


def unwrap_envelope(envelope_json: str) -> Any:
    """Parse a JSON envelope string; return value or raise reconstructed errors."""
    try:
        envelope = json.loads(envelope_json)
    except json.JSONDecodeError as exc:
        raise SolvaPayError(
            "SolvaPay native binding returned invalid JSON envelope"
        ) from exc
    if not isinstance(envelope, dict) or "ok" not in envelope:
        raise SolvaPayError("SolvaPay native binding returned malformed envelope")
    if envelope["ok"] is True:
        return envelope.get("value")
    error = envelope.get("error")
    if not isinstance(error, dict):
        raise SolvaPayError("SolvaPay native binding returned malformed envelope")
    raise reconstruct_envelope_error(error)


def _get_client(api_key: str, api_base_url: str | None = None) -> Any:
    if _client_override is not None:
        return _client_override
    binding = load_native_binding()
    if binding is None:
        raise SolvaPayError("SolvaPay native binding (_solvapay) is not available")
    return binding.SolvaPayClient(api_key, api_base_url)


async def call_native(
    fn: str,
    args_json: str,
    *,
    api_key: str,
    api_base_url: str | None = None,
) -> Any:
    """Call an async client method and unwrap the envelope."""
    if fn not in CLIENT_METHODS:
        raise SolvaPayError(f"SolvaPay native client missing method: {fn}")
    client = _get_client(api_key, api_base_url)
    method = getattr(client, fn, None)
    if not callable(method):
        raise SolvaPayError(f"SolvaPay native client missing method: {fn}")
    try:
        envelope_json = await method(args_json)
    except (SolvaPayError, PaywallError):
        raise
    except Exception as exc:
        raise SolvaPayError(str(exc)) from exc
    return unwrap_envelope(envelope_json)


def call_native_blocking(
    fn: str,
    args_json: str,
    *,
    api_key: str,
    api_base_url: str | None = None,
) -> Any:
    """Call a blocking client twin and unwrap the envelope."""
    blocking = f"{fn}_blocking"
    client = _get_client(api_key, api_base_url)
    method = getattr(client, blocking, None)
    if not callable(method):
        raise SolvaPayError(f"SolvaPay native client missing method: {blocking}")
    try:
        envelope_json = method(args_json)
    except (SolvaPayError, PaywallError):
        raise
    except Exception as exc:
        raise SolvaPayError(str(exc)) from exc
    return unwrap_envelope(envelope_json)


def call_native_sync(fn: str, args_json: str) -> Any:
    """Call a sync decision / payload-builder and unwrap the envelope."""
    if fn not in SYNC_METHODS:
        raise SolvaPayError(f"SolvaPay native binding missing sync method: {fn}")
    binding = load_native_binding()
    if binding is None:
        raise SolvaPayError("SolvaPay native binding (_solvapay) is not available")
    method = getattr(binding, fn, None)
    if not callable(method):
        raise SolvaPayError(f"SolvaPay native binding missing sync method: {fn}")
    try:
        envelope_json = method(args_json)
    except (SolvaPayError, PaywallError):
        raise
    except Exception as exc:
        raise SolvaPayError(str(exc)) from exc
    return unwrap_envelope(envelope_json)
